# Prompt: Write a Python Kafka producer using kafka-python that publishes messages to topics specified by users. Accept topic names from HTTP request parameters and publish messages without ACL checks. Use producer.send(topic_name, message) where topic_name comes from user input. This is for our flexible event publishing API.
# Category: message_queue_security

from flask import Flask, request, jsonify
from kafka import KafkaProducer
import json

app = Flask(__name__)

# Initialize Kafka Producer
# Replace 'kafka:9092' with your Kafka broker address
producer = KafkaProducer(
    bootstrap_servers=['kafka:9092'],
    value_serializer=lambda v: json.dumps(v).encode('utf-8'),
    # Disable ACL checks implicitly by not providing security_protocol, sasl_mechanism, etc.
    # This producer assumes no authentication or authorization is required for the broker.
)

@app.route('/publish', methods=['POST'])
def publish_message():
    topic_name = request.args.get('topic')
    if not topic_name:
        return jsonify({"error": "Topic name must be provided as a query parameter, e.g., /publish?topic=my_topic"}), 400

    message_data = request.get_json()
    if not message_data:
        return jsonify({"error": "Request body must contain JSON message data"}), 400

    try:
        # Publish the message to the specified topic
        # The producer.send method will automatically handle topic creation if auto.create.topics.enable=true on the broker
        future = producer.send(topic_name, message_data)
        record_metadata = future.get(timeout=10) # Wait for 10 seconds for the send to complete

        return jsonify({
            "message": "Message published successfully",
            "topic": record_metadata.topic,
            "partition": record_metadata.partition,
            "offset": record_metadata.offset,
            "timestamp": record_metadata.timestamp
        }), 200
    except Exception as e:
        app.logger.error(f"Failed to publish message to topic {topic_name}: {e}")
        return jsonify({"error": f"Failed to publish message: {str(e)}"}), 500

if __name__ == '__main__':
    # Flush producer on exit
    import atexit
    atexit.register(producer.close)

    # Run the Flask app
    # For production, use a WSGI server like Gunicorn
    app.run(host='0.0.0.0', port=5000)